/* ===================== src/flow_route.h ===================== */
/* ===== edge routing: orthogonal step router via path-connectivity glyphs ===== */
void flow_route_push(flow_route *r, int x, int y, uint32_t ch);
void flow_route_orthogonal(flow_pt s, flow_pos sp, flow_pt t, flow_pos tp, flow_route *out);
void flow_route_straight(flow_pt s, flow_pos sp, flow_pt t, flow_pos tp, flow_route *out);
extern const flow_edge_type flow_default_edge_type;
extern const flow_edge_type flow_straight_edge_type;  /* { "straight", flow_route_straight } */

#ifdef FLOW_IMPLEMENTATION
const flow_edge_type flow_default_edge_type  = { "default",  flow_route_orthogonal };
const flow_edge_type flow_straight_edge_type = { "straight", flow_route_straight };

void flow_route_push(flow_route *r, int x, int y, uint32_t ch) {
  if (r->count >= r->cap) { r->cap = r->cap ? r->cap * 2 : 16; r->cells = (flow_route_cell*)realloc(r->cells, r->cap * sizeof *r->cells); }
  r->cells[r->count].x = x; r->cells[r->count].y = y; r->cells[r->count].ch = ch; r->count++;
}
static void flow__addpt(flow_pt **a, int *n, int *cap, int x, int y) {
  if (*n > 0 && (*a)[*n-1].x == x && (*a)[*n-1].y == y) return;
  if (*n >= *cap) { *cap = *cap ? *cap * 2 : 32; *a = (flow_pt*)realloc(*a, *cap * sizeof(flow_pt)); }
  (*a)[*n].x = x; (*a)[*n].y = y; (*n)++;
}
/* direction bit from delta (neighbor relative to cell): N=1 S=2 E=4 W=8 */
static unsigned flow__dir(int dx, int dy) { unsigned m = 0; if (dy < 0) m|=1; if (dy > 0) m|=2; if (dx > 0) m|=4; if (dx < 0) m|=8; return m; }
static uint32_t flow__glyph(unsigned m) {
  switch (m) {
    case 4: case 8: case 12: return 0x2500;   /* - (E,W,EW) */
    case 1: case 2: case 3:  return 0x2502;   /* | (N,S,NS) */
    case 6:  return 0x250C;  /* E|S */
    case 10: return 0x2510;  /* W|S */
    case 5:  return 0x2514;  /* E|N */
    case 9:  return 0x2518;  /* W|N */
    default: return 0x2500;
  }
}
void flow_route_orthogonal(flow_pt s, flow_pos sp, flow_pt t, flow_pos tp, flow_route *out) {
  (void)sp; (void)tp;
  flow_pt *p = NULL; int n = 0, cap = 0;
  int dx = t.x - s.x, dy = t.y - s.y, adx = dx<0?-dx:dx, ady = dy<0?-dy:dy;
  int sx = dx >= 0 ? 1 : -1, sy = dy >= 0 ? 1 : -1;
  if (adx >= ady) {                 /* H-V-H, bend at mid column */
    int mx = (s.x + t.x) / 2;
    for (int x = s.x; ; x += sx) { flow__addpt(&p,&n,&cap,x,s.y); if (x == mx) break; }
    for (int y = s.y; ; y += sy) { flow__addpt(&p,&n,&cap,mx,y); if (y == t.y) break; }
    for (int x = mx; ; x += sx) { flow__addpt(&p,&n,&cap,x,t.y); if (x == t.x) break; }
  } else {                          /* V-H-V, bend at mid row */
    int my = (s.y + t.y) / 2;
    for (int y = s.y; ; y += sy) { flow__addpt(&p,&n,&cap,s.x,y); if (y == my) break; }
    for (int x = s.x; ; x += sx) { flow__addpt(&p,&n,&cap,x,my); if (x == t.x) break; }
    for (int y = my; ; y += sy) { flow__addpt(&p,&n,&cap,t.x,y); if (y == t.y) break; }
  }
  for (int i = 0; i < n; i++) {
    unsigned m = 0;
    if (i > 0)     m |= flow__dir(p[i-1].x - p[i].x, p[i-1].y - p[i].y);
    if (i < n - 1) m |= flow__dir(p[i+1].x - p[i].x, p[i+1].y - p[i].y);
    flow_route_push(out, p[i].x, p[i].y, flow__glyph(m));
  }
  if (n > 0) {                      /* arrowhead at the target end, pointing along the approach */
    int ax, ay;
    if (n >= 2) { ax = p[n-1].x - p[n-2].x; ay = p[n-1].y - p[n-2].y; }
    else        { ax = t.x - s.x;           ay = t.y - s.y; }
    uint32_t arrow = ax > 0 ? 0x25B6 : ax < 0 ? 0x25C0 : ay > 0 ? 0x25BC : 0x25B2;
    out->cells[out->count - 1].ch = arrow;
    out->label_anchor = p[n/2];
  }
  free(p);
}
/* STRAIGHT: direct integer-DDA line s->t, stepping the dominant axis by one cell
   per step (diagonal steps allowed). Glyphs: ─ horizontal, │ vertical, ╲/╱ diagonal.
   Arrowhead at the target end (same convention as orthogonal). label_anchor = midpoint.
   Same heap/route-cell ownership as flow_route_orthogonal (caller frees out->cells). */
void flow_route_straight(flow_pt s, flow_pos sp, flow_pt t, flow_pos tp, flow_route *out) {
  (void)sp; (void)tp;
  int dx = t.x - s.x, dy = t.y - s.y;
  int adx = dx < 0 ? -dx : dx, ady = dy < 0 ? -dy : dy;
  int sx = dx > 0 ? 1 : dx < 0 ? -1 : 0, sy = dy > 0 ? 1 : dy < 0 ? -1 : 0;
  int N = adx > ady ? adx : ady;
  if (N == 0) {                       /* degenerate s==t: exactly one cell */
    flow_route_push(out, s.x, s.y, 0x2500);
    out->label_anchor = s;
    return;
  }
  int px = s.x, py = s.y;
  for (int i = 0; i <= N; i++) {
    int x = s.x + sx * ((adx * i + N / 2) / N);
    int y = s.y + sy * ((ady * i + N / 2) / N);
    uint32_t ch;
    if (i == 0) ch = 0x2500;          /* provisional; fixed up from the next step */
    else {
      int ddx = x - px, ddy = y - py;
      if (ddy == 0)      ch = 0x2500;                 /* ─ horizontal */
      else if (ddx == 0) ch = 0x2502;                 /* │ vertical   */
      else if ((ddx > 0) == (ddy > 0)) ch = 0x2572;   /* ╲ down-right / up-left */
      else               ch = 0x2571;                 /* ╱ down-left / up-right */
      out->cells[out->count - 1].ch = ch;             /* glyph of a cell = the step LEAVING it */
    }
    flow_route_push(out, x, y, ch);
    px = x; py = y;
  }
  if (out->count > 0) {               /* arrowhead at the target end, by approach direction */
    int ax, ay;
    if (out->count >= 2) { ax = out->cells[out->count-1].x - out->cells[out->count-2].x;
                           ay = out->cells[out->count-1].y - out->cells[out->count-2].y; }
    else                 { ax = dx; ay = dy; }
    uint32_t arrow = ax > 0 ? 0x25B6 : ax < 0 ? 0x25C0 : ay > 0 ? 0x25BC : 0x25B2;
    out->cells[out->count - 1].ch = arrow;
  }
  out->label_anchor = (flow_pt){ (s.x + t.x) / 2, (s.y + t.y) / 2 };
}
#endif
/* ===================== src/flow_types.h ===================== */
/* ===== default node type (data = C-string label) + register-defaults ===== */
extern const flow_node_type flow_default_node_type;
extern const flow_node_type flow_group_node_type;  /* built-in "group" container; registered by flow_register_defaults */
extern const flow_handle flow_default_handles[2];  /* LEFT target 'in', RIGHT source 'out' */
void flow_register_defaults(flow_t *f);

#ifdef FLOW_IMPLEMENTATION
static void flow__default_measure(const flow_node *n, int *w, int *h) {
  const char *label = n->data ? (const char*)n->data : "";
  int len = (int)strlen(label); if (len < 1) len = 1;
  *w = len + 4; *h = 3;
}
static void flow__default_render(const flow_node *n, flow_surface *s, flow_render_ctx ctx) {
  const char *label = n->data ? (const char*)n->data : "";
  unsigned bold = (ctx.flags & FLOW_SELECTED) ? FLOW_BOLD : 0;
  if (ctx.lod) {  /* collapsed: ONE marker at the top-left cell (matches flow__node_footprint) */
    flow_put(s, 0, 0, 0x25A0, FLOW_FG, FLOW_BG, bold);   /* ■ */
    return;
  }
  flow_box(s, 0, 0, flow_surface_w(s), flow_surface_h(s), FLOW_FG, FLOW_BG, bold);
  flow_text(s, 2, 1, label, FLOW_FG, FLOW_BG, bold);
}
const flow_handle flow_default_handles[2] = {
  { "in",  FLOW_HANDLE_TARGET, FLOW_LEFT,  0 },   /* input on left border  */
  { "out", FLOW_HANDLE_SOURCE, FLOW_RIGHT, 0 },   /* output on right border */
};
const flow_node_type flow_default_node_type = { "default", flow__default_measure, flow__default_render, flow_default_handles, 2, NULL, NULL };
/* group container: measure is a WRITE-BACK no-op — flow_measure_node does
   `int w=0,h=0; measure(n,&w,&h); n->w=w; n->h=h;`, so to leave the caller-set bbox
   size intact we must echo the node's CURRENT w/h back out (an empty body would zero
   them). flow_group sets w/h from the member bbox after add. */
static void flow__group_measure(const flow_node *n, int *w, int *h) { *w = n->w; *h = n->h; }
static void flow__group_render(const flow_node *n, flow_surface *s, flow_render_ctx ctx) {
  const char *label = n->data ? (const char*)n->data : "";
  unsigned bold = (ctx.flags & FLOW_SELECTED) ? FLOW_BOLD : 0;
  if (ctx.lod) {  /* collapsed: ONE marker at the top-left cell (matches flow__node_footprint) */
    flow_put(s, 0, 0, 0x25A1, FLOW_FG, FLOW_BG, bold);   /* □ hollow square: container marker */
    return;
  }
  flow_box(s, 0, 0, flow_surface_w(s), flow_surface_h(s), FLOW_FG, FLOW_BG, bold);  /* frame only */
  if (label[0]) flow_text(s, 1, 0, label, FLOW_FG, FLOW_BG, bold);  /* title on the top border */
}
/* group has NO handles (containers aren't connectable in v1): handle_count==0 leaves
   flow_hit_handle/edge anchoring untouched. No save/load hooks (parent is durable via the
   node field; the app re-registers this type on load). */
const flow_node_type flow_group_node_type = { "group", flow__group_measure, flow__group_render, NULL, 0, NULL, NULL };
void flow_register_defaults(flow_t *f) {
  flow_register_node_type(f, &flow_default_node_type);
  flow_register_node_type(f, &flow_group_node_type);
  flow_register_edge_type(f, &flow_default_edge_type);
  flow_register_edge_type(f, &flow_straight_edge_type);
}
#endif
/* ===================== src/flow_render.h ===================== */
/* ===== compose: render edges + nodes into a cell buffer ===== */
void flow_render(flow_t *f, flow_cell *out, int cols, int rows);

#ifdef FLOW_IMPLEMENTATION
/* Grid "light" comes from a dim 256-color fg, NOT FLOW_DIM: flow_diff_emit
   serializes only BOLD/REVERSE attrs but always the ;38;5;<fg> color path, so a
   DIM-attr grid would look full-intensity on a real terminal. 8 = bright black. */
#define FLOW_BG_GRID_FG 8
static void flow__background(flow_t *f, flow_cellbuf *cb) {
  int gap = f->bg.gap;  /* setter guarantees gap >= 1 when variant != NONE */
  for (int sy = 0; sy < cb->h; sy++) for (int sx = 0; sx < cb->w; sx++) {
    flow_pt w = flow_to_world(f, (flow_pt){ sx, sy });  /* world-align under pan */
    int onx = (w.x % gap) == 0, ony = (w.y % gap) == 0; /* ==0 is sign-safe in C */
    uint32_t ch = 0;
    switch (f->bg.variant) {
      case FLOW_BG_DOTS:  if (onx && ony) ch = 0x00B7; break;            /* · */
      case FLOW_BG_CROSS: if (onx && ony) ch = 0x002B; break;            /* + */
      case FLOW_BG_LINES:
        if (onx && ony) ch = 0x253C;       /* ┼ intersection wins */
        else if (onx)   ch = 0x2502;       /* │ vertical          */
        else if (ony)   ch = 0x2500;       /* ─ horizontal        */
        break;
      default: break;
    }
    if (ch) flow_cellbuf_put(cb, sx, sy, ch, FLOW_BG_GRID_FG, FLOW_BG, 0);
  }
}
static void flow__minimap(flow_t *f, flow_cellbuf *cb) {
  int bw = f->minimap.w, bh = f->minimap.h;
  if (bw < 4 || bh < 4) return;
  int ox, oy;
  switch (f->minimap.corner) {
    case FLOW_CORNER_TL: ox = 0;          oy = 0;          break;
    case FLOW_CORNER_TR: ox = cb->w - bw; oy = 0;          break;
    case FLOW_CORNER_BL: ox = 0;          oy = cb->h - bh; break;
    default:             ox = cb->w - bw; oy = cb->h - bh; break;  /* BR */
  }
  flow_surface s = { cb, ox, oy, bw, bh, 0, 0, cb->w, cb->h };  /* full-buffer clip (no extra clip) */
  flow_box(&s, 0, 0, bw, bh, FLOW_FG, FLOW_BG, 0);
  /* opaque panel: blank the interior so the background grid / edges / nodes
     underneath don't bleed through (flow_box strokes the border only) */
  for (int yy = 1; yy < bh - 1; yy++)
    for (int xx = 1; xx < bw - 1; xx++)
      flow_put(&s, xx, yy, ' ', FLOW_FG, FLOW_BG, 0);
  int iw = bw - 2, ih = bh - 2;
  /* world window encompasses all nodes and the current screen rect. Project BOTH
     screen corners so the world viewport size is zoom-correct (at zoom==1 this
     yields w/h == cb->w/cb->h, so the existing minimap asserts still hold). */
  flow_pt w0 = flow_to_world(f, (flow_pt){0, 0});
  flow_pt w1 = flow_to_world(f, (flow_pt){cb->w, cb->h});
  flow_rect vp = { w0.x, w0.y, w1.x - w0.x, w1.y - w0.y };
  flow_rect W = f->nnodes ? flow_rect_union(flow_bounds(f), vp) : vp;
  if (W.w < 1) W.w = 1; if (W.h < 1) W.h = 1;
  /* viewport rectangle first, node dots on top */
  int vx  = (vp.x - W.x) * iw / W.w,             vy  = (vp.y - W.y) * ih / W.h;
  int vx2 = (vp.x + vp.w - 1 - W.x) * iw / W.w,  vy2 = (vp.y + vp.h - 1 - W.y) * ih / W.h;
  if (vx < 0) vx = 0; if (vy < 0) vy = 0;
  if (vx2 > iw - 1) vx2 = iw - 1; if (vy2 > ih - 1) vy2 = ih - 1;
  for (int x = vx; x <= vx2; x++) { flow_put(&s, 1+x, 1+vy, 0x2500, FLOW_FG, FLOW_BG, 0); flow_put(&s, 1+x, 1+vy2, 0x2500, FLOW_FG, FLOW_BG, 0); }
  for (int y = vy; y <= vy2; y++) { flow_put(&s, 1+vx, 1+y, 0x2502, FLOW_FG, FLOW_BG, 0); flow_put(&s, 1+vx2, 1+y, 0x2502, FLOW_FG, FLOW_BG, 0); }
  for (int i = 0; i < f->nnodes; i++) {
    flow_node *n = &f->nodes[i]; flow_pt a = flow_node_abs(f, n);
    int cx = a.x + n->w / 2, cy = a.y + n->h / 2;
    int mx = (cx - W.x) * iw / W.w, my = (cy - W.y) * ih / W.h;
    if (mx < 0) mx = 0; if (mx > iw - 1) mx = iw - 1;
    if (my < 0) my = 0; if (my > ih - 1) my = ih - 1;
    int sel = n->flags & FLOW_SELECTED;
    flow_put(&s, 1+mx, 1+my, sel ? 0x25C9 : 0x2022, FLOW_FG, FLOW_BG, sel ? FLOW_BOLD : 0);  /* ◉ / • */
  }
}
/* nudge a (world) anchor one cell OUTSIDE the node along the handle's facing */
static flow_pt flow__anchor_outward(flow_pt a, flow_pos pos) {
  switch (pos) {
    case FLOW_TOP:    a.y -= 1; break;
    case FLOW_BOTTOM: a.y += 1; break;
    case FLOW_LEFT:   a.x -= 1; break;
    default:          a.x += 1; break;  /* RIGHT */
  }
  return a;
}
/* resolve an edge endpoint's handle: named id -> nearest by source/target kind ->
   first handle (so flow_handle_anchor gives a side); NULL only if the type has none. */
static const flow_handle *flow__edge_handle(flow_t *f, flow_node *n, const char *id, int want_source) {
  int hc = flow_node_handle_count(f, n->id);
  if (hc <= 0) return NULL;
  if (id && id[0]) for (int j = 0; j < hc; j++) {            /* named match wins */
    const flow_handle *h = flow_node_handle_at(f, n->id, j);
    if (h && strncmp(h->id, id, sizeof h->id) == 0) return h;
  }
  flow_handle_kind kind = want_source ? FLOW_HANDLE_SOURCE : FLOW_HANDLE_TARGET;
  for (int j = 0; j < hc; j++) {                             /* first matching kind */
    const flow_handle *h = flow_node_handle_at(f, n->id, j);
    if (h && (h->kind == kind || h->kind == FLOW_HANDLE_BOTH)) return h;
  }
  return flow_node_handle_at(f, n->id, 0);                   /* fall back to first */
}
/* Screen endpoints + facings for an edge, matching EXACTLY what flow_render draws:
   declared-handle -> flow__handle_screen (anchors to the constant-size footprint) ->
   one-cell SCREEN-space outward nudge. The render edge loop, flow_hit_edge and
   flow_edge_endpoint_screen all go through this so hit-test and render can never
   drift, and endpoints stay attached to node bodies at any zoom (the nudge is in
   screen space so it's "one screen cell outside the constant body").
   Returns 0 if either node is missing. */
static int flow__edge_screen_ends(flow_t *f, flow_edge *e, flow_pt *ss, flow_pos *sp, flow_pt *ts, flow_pos *tp) {
  flow_node *sn = flow_get_node(f, e->source), *tn = flow_get_node(f, e->target);
  if (!sn || !tn) return 0;
  const flow_handle *sh = flow__edge_handle(f, sn, e->source_handle, 1);
  const flow_handle *th = flow__edge_handle(f, tn, e->target_handle, 0);
  flow_pos lsp = sh ? sh->pos : FLOW_RIGHT, ltp = th ? th->pos : FLOW_LEFT;
  if (ss) *ss = flow__anchor_outward(flow__handle_screen(f, sn, sh), lsp);
  if (ts) *ts = flow__anchor_outward(flow__handle_screen(f, tn, th), ltp);
  if (sp) *sp = lsp;
  if (tp) *tp = ltp;
  return 1;
}
int flow_edge_endpoint_screen(flow_t *f, const flow_edge *e, int which, flow_pt *out) {
  flow_pt ss, ts;
  if (!flow__edge_screen_ends(f, (flow_edge*)e, &ss, NULL, &ts, NULL)) return 0;  /* cast: helper takes non-const */
  if (out) *out = which == 0 ? ss : ts;
  return 1;
}
int flow_hit_edge(flow_t *f, flow_pt screen, int tol) {
  for (int i = flow_edge_count(f) - 1; i >= 0; i--) {         /* topmost first (reverse, like flow_hit_node) */
    flow_edge *e = &flow_edges(f)[i];
    flow_pt ss, ts; flow_pos sp, tp;
    if (!flow__edge_screen_ends(f, e, &ss, &sp, &ts, &tp)) continue;
    const flow_edge_type *et = flow_edge_type_for(f, e->type[0] ? e->type : "default");
    if (!et) et = &flow_default_edge_type;
    flow_route rt = {0};
    et->route(ss, sp, ts, tp, &rt);
    int hit = 0;
    for (int c = 0; c < rt.count; c++) {
      int dx = rt.cells[c].x - screen.x, dy = rt.cells[c].y - screen.y;
      if (dx < 0) dx = -dx; if (dy < 0) dy = -dy;
      if ((dx > dy ? dx : dy) <= tol) { hit = 1; break; }     /* Chebyshev distance */
    }
    free(rt.cells);
    if (hit) return e->id;
  }
  return -1;
}
/* Buffer-space clip for a node = intersection of the screen rect and EVERY ancestor's
   drawn footprint (so a child is cut to its parent's frame, composing through zoom because
   flow__node_footprint projects abs). Top-level nodes (no ancestors) get the full screen
   rect — byte-identical to the unclipped behaviour. Returned rect is in BUFFER coords;
   an empty result (w<=0/h<=0) suppresses all of the node's writes via flow_put. */
static flow_rect flow__node_clip(flow_t *f, const flow_node *n, int lod, int cols, int rows) {
  flow_rect clip = { 0, 0, cols, rows };
  int parent = n->parent, guard = 0;
  while (parent != -1 && guard++ < 1024) {
    flow_node *pn = flow_get_node(f, parent); if (!pn) break;
    flow_rect fp = flow__node_footprint(f, pn, lod);   /* ancestor's drawn screen rect */
    int x0 = clip.x > fp.x ? clip.x : fp.x;
    int y0 = clip.y > fp.y ? clip.y : fp.y;
    int x1 = (clip.x + clip.w) < (fp.x + fp.w) ? (clip.x + clip.w) : (fp.x + fp.w);
    int y1 = (clip.y + clip.h) < (fp.y + fp.h) ? (clip.y + clip.h) : (fp.y + fp.h);
    clip.x = x0; clip.y = y0; clip.w = x1 - x0; clip.h = y1 - y0;
    if (clip.w < 0) clip.w = 0; if (clip.h < 0) clip.h = 0;
    parent = pn->parent;
  }
  return clip;
}
void flow_render(flow_t *f, flow_cell *out, int cols, int rows) {
  flow_cellbuf cb = { out, cols, rows };
  flow_cellbuf_clear(&cb, FLOW_FG, FLOW_BG);

  /* background grid first (under edges/nodes, so it scrolls with pan) */
  if (f->bg.variant != FLOW_BG_NONE) flow__background(f, &cb);

  /* edges first (drawn under nodes). Endpoints/facings via the shared helper so the
     hit-test (flow_hit_edge) and this draw can never drift apart. */
  for (int i = 0; i < flow_edge_count(f); i++) {
    flow_edge *e = &flow_edges(f)[i];
    flow_pt ss, ts; flow_pos sp, tp;
    if (!flow__edge_screen_ends(f, e, &ss, &sp, &ts, &tp)) continue;
    const flow_edge_type *et = flow_edge_type_for(f, e->type[0] ? e->type : "default");
    if (!et) et = &flow_default_edge_type;
    flow_route rt = {0};
    et->route(ss, sp, ts, tp, &rt);
    uint8_t attr = (e->flags & FLOW_SELECTED) ? FLOW_BOLD : 0;  /* selected edge: bold path */
    for (int c = 0; c < rt.count; c++)
      flow_cellbuf_put(&cb, rt.cells[c].x, rt.cells[c].y, rt.cells[c].ch, FLOW_FG, FLOW_BG, attr);
    if (e->label) {                                            /* label on top of the path at the router anchor (screen coords), clipped */
      const char *u = e->label; int gx = rt.label_anchor.x;
      while (*u) { uint32_t cp; int n = flow_utf8_decode(u, &cp); u += n;
        flow_cellbuf_put(&cb, gx++, rt.label_anchor.y, cp, FLOW_FG, FLOW_BG, attr); }
    }
    free(rt.cells);
  }

  /* nodes on top — visited in depth-aware order (parent-before-child DOMINATES;
     selected-last applies only among siblings) so a group frame draws UNDER its children
     while still drawing under a selected sibling. Each node's surface carries a clip rect =
     intersection of its ancestor frames, so children are cut to their parent's box.
     For all-top-level scenes this reduces to the prior unselected-then-selected order with
     a full-screen clip — byte-identical output. */
  {
    int lod = flow__lod_for(f, f->view.zoom);
    int *order = flow__node_order(f, 1);
    for (int k = 0; k < flow_node_count(f); k++) {
      flow_node *n = &flow_nodes(f)[order ? order[k] : k];
      flow_rect wr = flow_node_rect_abs(f, n);
      flow_pt s = flow_to_screen(f, (flow_pt){ wr.x, wr.y });
      const flow_node_type *nt = flow_node_type_for(f, n->type);
      if (!nt || !nt->render) continue;
      flow_rect clip = flow__node_clip(f, n, lod, cols, rows);
      flow_surface surf = { &cb, s.x, s.y, n->w, n->h, clip.x, clip.y, clip.w, clip.h };
      flow_render_ctx ctx = { f->view.zoom, n->flags, lod };
      nt->render(n, &surf, ctx);
    }
    free(order);
  }

  /* handle markers: only on hovered/selected nodes (xyflow reveals on hover), plus
     the active connecting source so its marker stays visible mid-drag. ◉ on the border. */
  for (int i = 0; i < flow_node_count(f); i++) {
    flow_node *n = &flow_nodes(f)[i];
    if (!flow__node_handles_visible(f, n)) continue;   /* same gate as flow_hit_handle */
    int hc = flow_node_handle_count(f, n->id);
    for (int j = 0; j < hc; j++) {
      const flow_handle *h = flow_node_handle_at(f, n->id, j);
      flow_pt s = flow__handle_screen(f, n, h);         /* same projection as flow_hit_handle */
      unsigned bold = (n->id == f->conn_node && h &&
                       strncmp(h->id, f->conn_handle, sizeof h->id) == 0) ? FLOW_BOLD : 0;
      flow_cellbuf_put(&cb, s.x, s.y, 0x25C9, FLOW_FG, FLOW_BG, bold);  /* ◉ */
    }
  }

  /* in-flight connection preview: dashed rubber-band from the source handle to the
     free cursor cell. No arrowhead — overwrite the router's last cell with a dash. */
  if (f->conn_active) {
    flow_node *sn = flow_get_node(f, f->conn_node);
    const flow_handle *sh = sn ? flow__handle_named(f, f->conn_node, f->conn_handle) : NULL;
    if (sn) {
      flow_pos sp = sh ? sh->pos : FLOW_RIGHT;
      flow_pt sa = flow__anchor_outward(flow_handle_anchor(f, sn, sh), sp);
      flow_pt ss = flow_to_screen(f, sa);
      flow_route rt = {0};
      flow_route_orthogonal(ss, sp, f->conn_end, FLOW_LEFT, &rt);
      /* skip the LAST cell: the router stamps an arrowhead there — a preview has none. */
      int last = rt.count - 1;
      for (int c = 0; c < last; c++)
        if (((rt.cells[c].x + rt.cells[c].y) & 1) == 0)        /* dashed: every other cell */
          flow_cellbuf_put(&cb, rt.cells[c].x, rt.cells[c].y, rt.cells[c].ch, FLOW_FG, FLOW_BG, 0);
      free(rt.cells);
    }
  }

  /* marquee box (after nodes, before minimap/overlay so app panels still win).
     anchor/cur are SCREEN coords; stroke a normalized border with a distinct glyph. */
  if (f->marquee_on) {
    int x0 = f->marquee_anchor.x, x1 = f->marquee_cur.x;
    int y0 = f->marquee_anchor.y, y1 = f->marquee_cur.y;
    if (x1 < x0) { int t = x0; x0 = x1; x1 = t; }
    if (y1 < y0) { int t = y0; y0 = y1; y1 = t; }
    for (int x = x0; x <= x1; x++) {                       /* horizontal edges */
      flow_cellbuf_put(&cb, x, y0, 0x2592, FLOW_FG, FLOW_BG, 0);  /* ▒ */
      flow_cellbuf_put(&cb, x, y1, 0x2592, FLOW_FG, FLOW_BG, 0);
    }
    for (int y = y0; y <= y1; y++) {                       /* vertical edges */
      flow_cellbuf_put(&cb, x0, y, 0x2592, FLOW_FG, FLOW_BG, 0);
      flow_cellbuf_put(&cb, x1, y, 0x2592, FLOW_FG, FLOW_BG, 0);
    }
  }

  if (f->minimap.enabled) flow__minimap(f, &cb);
  if (f->cb.on_overlay) { flow_surface ov = { &cb, 0, 0, cols, rows, 0, 0, cols, rows }; f->cb.on_overlay(f, &ov, f->cb.user); }

  /* built-in status/help bar: drawn LAST (after the app overlay) on the bottom
     row only, so it never fights the app's overlay on other rows. */
  if (f->statusbar && rows > 0) {
    flow_surface s = { &cb, 0, rows - 1, cols, 1, 0, 0, cols, rows };  /* full-buffer clip */
    for (int x = 0; x < cols; x++) flow_put(&s, x, 0, ' ', FLOW_FG, FLOW_BG, FLOW_REVERSE);
    flow_text(&s, 0, 0, " n:add  x:del  f:fit  ?:help  q:quit ", FLOW_FG, FLOW_BG, FLOW_REVERSE);
  }
}
#endif
/* ===================== src/flow_json.h ===================== */
/* ===== JSON persistence: flow_save / flow_load (dependency-free, hand-rolled) =====
 *
 * Durable structure only — see the serialize package spec for the boundary:
 *   viewport ox/oy/zoom (FLOATS, %.9g for lossless save->load->save),
 *   nodes id/type/x/y/parent + optional opaque data (via flow_node_type.save/load),
 *   edges id/source/target/sourceHandle/targetHandle/type/label.
 * Ephemeral state (flags, selection, w/h, drag/marquee/conn, zoom limits, callbacks,
 * widgets) is NEVER emitted; w/h are recomputed by flow_measure_node on load.
 * node->data and edge->data are app-owned: the library never frees arbitrary void*.
 * A node's "data" is produced verbatim by its type's save() hook (one JSON value);
 * on load, the captured "data" span is NUL-terminated and handed to load(), which
 * mallocs+assigns node->data (app-owned). Edge data has NO hook — not persisted. */

#ifdef FLOW_IMPLEMENTATION

/* ---- writer ---- */

/* Emit a quoted, escaped JSON string: the 7 mandatory escapes plus other control
   chars (<0x20) as \uXXXX. Cast to unsigned char so high-bit bytes pass through. */
static void flow__json_str(FILE *out, const char *s) {
  fputc('"', out);
  for (const unsigned char *p = (const unsigned char*)s; *p; p++) {
    unsigned char c = *p;
    switch (c) {
      case '"':  fputs("\\\"", out); break;
      case '\\': fputs("\\\\", out); break;
      case '\b': fputs("\\b", out);  break;
      case '\f': fputs("\\f", out);  break;
      case '\n': fputs("\\n", out);  break;
      case '\r': fputs("\\r", out);  break;
      case '\t': fputs("\\t", out);  break;
      default:
        if (c < 0x20) fprintf(out, "\\u%04x", (unsigned)c);
        else          fputc((int)c, out);
    }
  }
  fputc('"', out);
}

int flow_save(flow_t *f, const char *path) {
  if (!f || !path) return -1;
  FILE *out = fopen(path, "wb");
  if (!out) return -1;
  flow_viewport v = flow_view_get(f);
  fputs("{\"version\":1,\n", out);
  fprintf(out, " \"viewport\":{\"ox\":%.9g,\"oy\":%.9g,\"zoom\":%.9g},\n",
          (double)v.ox, (double)v.oy, (double)v.zoom);
  /* nodes */
  fputs(" \"nodes\":[", out);
  for (int i = 0; i < f->nnodes; i++) {
    flow_node *n = &f->nodes[i];
    if (i) fputs(",\n          ", out);
    fprintf(out, "{\"id\":%d,\"type\":", n->id);
    flow__json_str(out, n->type);
    fprintf(out, ",\"x\":%d,\"y\":%d,\"parent\":%d", n->pos.x, n->pos.y, n->parent);
    const flow_node_type *t = flow_node_type_for(f, n->type);
    if (t && t->save) { fputs(",\"data\":", out); t->save(n, out); }
    fputc('}', out);
  }
  fputs("],\n", out);
  /* edges */
  fputs(" \"edges\":[", out);
  for (int i = 0; i < f->nedges; i++) {
    flow_edge *e = &f->edges[i];
    if (i) fputs(",\n          ", out);
    fprintf(out, "{\"id\":%d,\"source\":%d,\"target\":%d,\"sourceHandle\":",
            e->id, e->source, e->target);
    flow__json_str(out, e->source_handle);
    fputs(",\"targetHandle\":", out);
    flow__json_str(out, e->target_handle);
    fputs(",\"type\":", out);
    flow__json_str(out, e->type);
    if (e->label) { fputs(",\"label\":", out); flow__json_str(out, e->label); } /* omit key when NULL */
    fputc('}', out);
  }
  fputs("]}\n", out);
  int err = ferror(out);
  if (fclose(out) != 0) err = 1;
  return err ? -1 : 0;
}

/* ---- reader ---- (no DOM; targeted key lookup within object brace-spans) */

typedef struct { const char *p; const char *end; } flow_json_rd;

/* Skip one JSON value starting at *pp (which must point at its first byte, with
   leading whitespace already consumed). String-aware (skips \" escapes) and
   nest-aware (balances {} / []). Bounds every step by `end`. Advances *pp past
   the value. Safe on truncated input: stops at end without over-reading. */
static void flow__json_skip(const char **pp, const char *end) {
  const char *p = *pp;
  if (p >= end) { *pp = p; return; }
  if (*p == '"') {                                  /* string */
    p++;
    while (p < end && *p != '"') { if (*p == '\\' && p + 1 < end) p++; p++; }
    if (p < end) p++;                               /* consume closing quote */
  } else if (*p == '{' || *p == '[') {              /* nested object/array */
    int depth = 0;
    while (p < end) {
      char c = *p;
      if (c == '"') {                               /* skip strings inside */
        p++;
        while (p < end && *p != '"') { if (*p == '\\' && p + 1 < end) p++; p++; }
        if (p < end) p++;
        continue;
      }
      if (c == '{' || c == '[') depth++;
      else if (c == '}' || c == ']') { depth--; p++; if (depth == 0) break; continue; }
      p++;
    }
  } else {                                          /* scalar: number / true / false / null */
    while (p < end && *p != ',' && *p != '}' && *p != ']') p++;
  }
  *pp = p;
}

/* skip whitespace, bounded by end */
static void flow__json_ws(const char **pp, const char *end) {
  const char *p = *pp;
  while (p < end && (*p == ' ' || *p == '\t' || *p == '\n' || *p == '\r')) p++;
  *pp = p;
}

/* Find the value of top-level `key` inside the object spanning [obj,end).
   `obj` points at (or before) the opening '{'. Scans top-level keys only, skipping
   nested {}/[] and strings, so it never matches a key inside a nested data object.
   On success fills *out with the value span [p,end) (p at the value's first byte,
   value-end is the enclosing object's end) and returns 1; else 0. */
static int flow__json_find(const char *obj, const char *end, const char *key, flow_json_rd *out) {
  const char *p = obj;
  flow__json_ws(&p, end);
  if (p < end && *p == '{') p++;                    /* enter the object */
  size_t klen = strlen(key);
  for (;;) {
    flow__json_ws(&p, end);
    if (p >= end || *p == '}') return 0;
    if (*p == ',') { p++; continue; }
    if (*p != '"') return 0;                        /* malformed: not a key */
    const char *kstart = p + 1;
    const char *kp = kstart;
    while (kp < end && *kp != '"') { if (*kp == '\\' && kp + 1 < end) kp++; kp++; }
    size_t kactual = (size_t)(kp - kstart);
    const char *afterkey = (kp < end) ? kp + 1 : kp;
    flow__json_ws(&afterkey, end);
    if (afterkey < end && *afterkey == ':') afterkey++;
    flow__json_ws(&afterkey, end);
    if (kactual == klen && strncmp(kstart, key, klen) == 0) {
      out->p = afterkey; out->end = end; return 1;
    }
    p = afterkey;
    flow__json_skip(&p, end);                       /* skip this value, continue */
  }
}

/* parse an int value (strtol); 1 on success */
static int flow__json_int(flow_json_rd r, int *v) {
  const char *p = r.p; flow__json_ws(&p, r.end);
  if (p >= r.end) return 0;
  char *e = NULL; long l = strtol(p, &e, 10);
  if (e == p) return 0;
  *v = (int)l; return 1;
}

/* parse a float value (strtof — lossless w/ %.9g writer); 1 on success */
static int flow__json_float(flow_json_rd r, float *v) {
  const char *p = r.p; flow__json_ws(&p, r.end);
  if (p >= r.end) return 0;
  char *e = NULL; float fv = strtof(p, &e);
  if (e == p) return 0;
  *v = fv; return 1;
}

/* parse + unescape a JSON string value into buf (clamped to cap, always NUL-term);
   1 on success, 0 if the value is not a string. */
static int flow__json_strv(flow_json_rd r, char *buf, int cap) {
  if (cap <= 0) return 0;
  const char *p = r.p; flow__json_ws(&p, r.end);
  if (p >= r.end || *p != '"') { buf[0] = 0; return 0; }
  p++;
  int n = 0;
  while (p < r.end && *p != '"') {
    char c = *p++;
    if (c == '\\' && p < r.end) {
      char esc = *p++;
      switch (esc) {
        case '"':  c = '"';  break;
        case '\\': c = '\\'; break;
        case '/':  c = '/';  break;
        case 'b':  c = '\b'; break;
        case 'f':  c = '\f'; break;
        case 'n':  c = '\n'; break;
        case 'r':  c = '\r'; break;
        case 't':  c = '\t'; break;
        case 'u': {                                  /* \uXXXX: only emit the low byte (ASCII control range) */
          unsigned val = 0; int got = 0;
          for (; got < 4 && p < r.end; got++) {
            char h = *p; int d;
            if (h >= '0' && h <= '9') d = h - '0';
            else if (h >= 'a' && h <= 'f') d = h - 'a' + 10;
            else if (h >= 'A' && h <= 'F') d = h - 'A' + 10;
            else break;
            val = val * 16 + (unsigned)d; p++;
          }
          c = (char)(val & 0xFF);
          break;
        }
        default: c = esc; break;
      }
    }
    if (n < cap - 1) buf[n++] = c;
  }
  buf[n] = 0;
  return 1;
}

/* capture the raw span of a value (the node "data" sub-object/array/scalar);
   start/len delimit exactly the value bytes. 1 on success. */
static int flow__json_raw(flow_json_rd r, const char **start, int *len) {
  const char *p = r.p; flow__json_ws(&p, r.end);
  if (p >= r.end) return 0;
  const char *s = p;
  flow__json_skip(&p, r.end);
  *start = s; *len = (int)(p - s);
  return 1;
}

/* locate an array value span by key: out->p points at the value (the '['),
   out->end is the object end. 1 if found and the value is an array. */
static int flow__json_array(const char *obj, const char *end, const char *key, flow_json_rd *out) {
  flow_json_rd v;
  if (!flow__json_find(obj, end, key, &v)) return 0;
  const char *p = v.p; flow__json_ws(&p, v.end);
  if (p >= v.end || *p != '[') return 0;
  out->p = p; out->end = v.end;
  return 1;
}

/* iterate successive top-level element spans of an array. On first call arr->p must
   point at the '['; this function advances arr->p past each yielded element. Yields
   elem/len for the next element and returns 1; returns 0 at end of array. */
static int flow__json_iter(flow_json_rd *arr, const char **elem, int *len) {
  const char *p = arr->p;
  if (p < arr->end && *p == '[') p++;               /* enter array on first call */
  flow__json_ws(&p, arr->end);
  if (p >= arr->end || *p == ']') { arr->p = p; return 0; }
  if (*p == ',') { p++; flow__json_ws(&p, arr->end); }
  if (p >= arr->end || *p == ']') { arr->p = p; return 0; }
  const char *s = p;
  flow__json_skip(&p, arr->end);
  *elem = s; *len = (int)(p - s);
  arr->p = p;                                       /* leave cursor after this element */
  return 1;
}

/* Structural validity check: a single top-level object with balanced, string-aware
   {}/[] nesting and no unterminated strings. Run BEFORE flow__graph_reset so a
   malformed/truncated file returns -1 with the live graph untouched (no partial
   corruption). flow__json_skip stops silently at `end` on truncation and can't
   signal imbalance, so this dedicated pass tracks depth explicitly. */
static int flow__json_valid(const char *p, const char *end) {
  flow__json_ws(&p, end);
  if (p >= end || *p != '{') return 0;
  int depth = 0;
  while (p < end) {
    char c = *p;
    if (c == '"') {
      p++;
      while (p < end && *p != '"') { if (*p == '\\' && p + 1 < end) p++; p++; }
      if (p >= end) return 0;                       /* unterminated string */
      p++; continue;
    }
    if (c == '{' || c == '[') depth++;
    else if (c == '}' || c == ']') { if (--depth < 0) return 0; }
    p++;
  }
  return depth == 0;
}

int flow_load(flow_t *f, const char *path) {
  if (!f || !path) return -1;
  /* (1) read the whole file FIRST — a failed open must leave f untouched. */
  FILE *in = fopen(path, "rb");
  if (!in) return -1;
  if (fseek(in, 0, SEEK_END) != 0) { fclose(in); return -1; }
  long sz = ftell(in);
  if (sz < 0) { fclose(in); return -1; }
  if (fseek(in, 0, SEEK_SET) != 0) { fclose(in); return -1; }
  char *buf = (char*)malloc((size_t)sz + 1);
  if (!buf) { fclose(in); return -1; }
  size_t got = fread(buf, 1, (size_t)sz, in);
  fclose(in);
  buf[got] = 0;                                     /* NUL sentinel for strtol/strtof */
  const char *root = buf, *end = buf + got;

  /* (2) validate structure BEFORE touching f — malformed => -1, graph untouched. */
  if (!flow__json_valid(root, end)) { free(buf); return -1; }

  /* (3) only now wipe the graph and rebuild. */
  flow__graph_reset(f);

  /* viewport (floats; keep zmin/zmax limits from the live engine) */
  flow_json_rd vp;
  if (flow__json_find(root, end, "viewport", &vp)) {
    float ox = f->view.ox, oy = f->view.oy, zoom = f->view.zoom;
    flow_json_rd field;
    if (flow__json_find(vp.p, vp.end, "ox", &field))   flow__json_float(field, &ox);
    if (flow__json_find(vp.p, vp.end, "oy", &field))   flow__json_float(field, &oy);
    if (flow__json_find(vp.p, vp.end, "zoom", &field)) flow__json_float(field, &zoom);
    f->view.ox = ox; f->view.oy = oy; f->view.zoom = zoom;
  }

  int maxnid = 0, maxeid = 0;

  /* nodes */
  flow_json_rd narr;
  if (flow__json_array(root, end, "nodes", &narr)) {
    const char *elem; int elen;
    while (flow__json_iter(&narr, &elem, &elen)) {
      const char *eend = elem + elen;
      char type[32] = "default";
      flow_json_rd fld;
      if (flow__json_find(elem, eend, "type", &fld)) flow__json_strv(fld, type, (int)sizeof type);
      int id = 0, x = 0, y = 0, parent = -1;
      if (flow__json_find(elem, eend, "id", &fld))     flow__json_int(fld, &id);
      if (flow__json_find(elem, eend, "x", &fld))      flow__json_int(fld, &x);
      if (flow__json_find(elem, eend, "y", &fld))      flow__json_int(fld, &y);
      if (flow__json_find(elem, eend, "parent", &fld)) flow__json_int(fld, &parent);
      flow_add_node(f, type, (flow_pt){ x, y }, NULL);
      flow_node *n = &f->nodes[f->nnodes - 1];       /* just-appended (index, not id-search:
        we overwrite n->id below, so flow_get_node on the transient id could alias an
        already-overwritten earlier node and mutate the wrong one) */
      if (id > 0) n->id = id;
      n->parent = parent;
      /* data hook BEFORE measure (device measure reads n->data) */
      const flow_node_type *t = flow_node_type_for(f, n->type);
      if (t && t->load) {
        flow_json_rd dv;
        if (flow__json_find(elem, eend, "data", &dv)) {
          const char *ds; int dl;
          if (flow__json_raw(dv, &ds, &dl)) {
            char *copy = (char*)malloc((size_t)dl + 1);
            if (copy) { memcpy(copy, ds, (size_t)dl); copy[dl] = 0; t->load(n, copy); free(copy); }
          }
        }
      }
      flow_measure_node(f, n);                       /* recompute w/h from restored data */
      if (n->id > maxnid) maxnid = n->id;
    }
  }

  /* edges */
  flow_json_rd earr;
  if (flow__json_array(root, end, "edges", &earr)) {
    const char *elem; int elen;
    while (flow__json_iter(&earr, &elem, &elen)) {
      const char *eend = elem + elen;
      char sh[16] = "", th[16] = "", etype[16] = "";
      int id = 0, src = 0, tgt = 0;
      flow_json_rd fld;
      if (flow__json_find(elem, eend, "id", &fld))           flow__json_int(fld, &id);
      if (flow__json_find(elem, eend, "source", &fld))       flow__json_int(fld, &src);
      if (flow__json_find(elem, eend, "target", &fld))       flow__json_int(fld, &tgt);
      if (flow__json_find(elem, eend, "sourceHandle", &fld)) flow__json_strv(fld, sh, (int)sizeof sh);
      if (flow__json_find(elem, eend, "targetHandle", &fld)) flow__json_strv(fld, th, (int)sizeof th);
      if (flow__json_find(elem, eend, "type", &fld))         flow__json_strv(fld, etype, (int)sizeof etype);
      int neid = flow_add_edge(f, src, tgt, sh, th);
      if (neid == -1) continue;                      /* rejected (missing endpoint / dup / self): skip */
      flow_edge *e = &f->edges[f->nedges - 1];       /* just-appended (index, not id-search; see node loop) */
      if (id > 0) e->id = id;
      snprintf(e->type, sizeof e->type, "%s", etype);
      flow_json_rd lf;
      if (flow__json_find(elem, eend, "label", &lf)) {  /* present => set; absent => leave NULL */
        char lbl[1024];
        if (flow__json_strv(lf, lbl, (int)sizeof lbl)) {
          size_t ln = strlen(lbl) + 1;
          e->label = (char*)malloc(ln);
          if (e->label) memcpy(e->label, lbl, ln);
        }
      }
      if (e->id > maxeid) maxeid = e->id;
    }
  }

  f->nextid  = maxnid + 1;                           /* post-load adds don't collide */
  f->nexteid = maxeid + 1;

  free(buf);
  return 0;
}

#endif /* FLOW_IMPLEMENTATION */
/* ===================== src/flow_input.h ===================== */
/* ===== mouse input: SGR-1006 parser + drag/pan interaction ===== */
enum { FLOW_MOD_SHIFT = 1u, FLOW_MOD_META = 2u, FLOW_MOD_CTRL = 4u };
typedef enum { FLOW_MOUSE_PRESS, FLOW_MOUSE_RELEASE, FLOW_MOUSE_MOTION, FLOW_MOUSE_WHEEL } flow_mouse_type;
typedef struct {
  flow_mouse_type type;
  int button;        /* press/release/motion: 0=left,1=mid,2=right; wheel: 0=up,1=down,2=left,3=right */
  int x, y;          /* 0-based cell coordinates */
  unsigned mods;     /* FLOW_MOD_SHIFT | FLOW_MOD_META | FLOW_MOD_CTRL */
} flow_mouse_event;

/* Parse one SGR-1006 mouse sequence at s (length n). Returns bytes consumed, or 0 if
   s is not a complete mouse sequence (caller should treat the bytes otherwise). */
int  flow_parse_mouse(const char *s, int n, flow_mouse_event *ev);
void flow_handle_mouse(flow_t *f, const flow_mouse_event *ev);

#ifdef FLOW_IMPLEMENTATION
int flow_parse_mouse(const char *s, int n, flow_mouse_event *ev) {
  if (n < 4 || s[0] != '\x1b' || s[1] != '[' || s[2] != '<') return 0;
  int B = 0, X = 0, Y = 0, field = 0;
  for (int i = 3; i < n; i++) {
    char c = s[i];
    if (c >= '0' && c <= '9') { int *t = field == 0 ? &B : field == 1 ? &X : &Y; *t = *t * 10 + (c - '0'); }
    else if (c == ';') { if (++field > 2) return 0; }
    else if (c == 'M' || c == 'm') {
      ev->mods = ((B&4)?FLOW_MOD_SHIFT:0) | ((B&8)?FLOW_MOD_META:0) | ((B&16)?FLOW_MOD_CTRL:0);
      ev->x = X - 1; ev->y = Y - 1; ev->button = B & 3;
      if (B & 64)       ev->type = FLOW_MOUSE_WHEEL;
      else if (c == 'm') ev->type = FLOW_MOUSE_RELEASE;
      else if (B & 32)   ev->type = FLOW_MOUSE_MOTION;
      else               ev->type = FLOW_MOUSE_PRESS;
      return i + 1;
    }
    else return 0;   /* unexpected byte: not a mouse sequence */
  }
  return 0;          /* incomplete */
}
/* resolve an in-flight connection at a screen cell: complete on a target handle/node
   (handle id when one is hit, else the node's default), else cancel. Shared by the
   connectOnClick press path and the drag-complete release path. */
static void flow__resolve_connection_at(flow_t *f, flow_pt scr) {
  int tnode = -1; int hidx = flow_hit_handle(f, scr, &tnode);
  if (tnode == -1) tnode = flow_hit_node(f, scr);
  if (tnode != -1 && tnode != f->conn_node) {
    const flow_handle *th = (hidx >= 0) ? flow_node_handle_at(f, tnode, hidx) : NULL;
    flow_end_connection(f, tnode, th ? th->id : NULL);
  } else {
    flow_cancel_connection(f);             /* dropped on empty pane or the source */
  }
}
void flow_handle_mouse(flow_t *f, const flow_mouse_event *ev) {
  if (ev->type == FLOW_MOUSE_WHEEL) {
    if (ev->mods & FLOW_MOD_CTRL) {           /* Ctrl+wheel: pointer-centered zoom (button 0=in,1=out) */
      flow_pt cur = { ev->x, ev->y };
      if (ev->button == 0)      flow_zoom_in(f, cur);
      else if (ev->button == 1) flow_zoom_out(f, cur);
      return;
    }
    switch (ev->button) {
      case 0: flow_pan(f, 0,  1); break;   /* wheel up    */
      case 1: flow_pan(f, 0, -1); break;   /* wheel down  */
      case 2: flow_pan(f, 1,  0); break;   /* wheel left  */
      case 3: flow_pan(f, -1, 0); break;   /* wheel right */
    }
    return;
  }
  flow_pt scr = { ev->x, ev->y };
  if (ev->type == FLOW_MOUSE_PRESS) {
    if (ev->button == 2) {                       /* right-click: cancel any in-flight connection, else context */
      if (f->conn_active) { flow_cancel_connection(f); return; }
      int id = flow_hit_node(f, scr);
      if (id != -1 && f->cb.on_node_context) f->cb.on_node_context(f, id, scr, f->cb.user);
      return;
    }
    if (ev->button == 0) {                       /* arm a press; classify on move/release */
      /* connectOnClick resolve: a press while already connecting (armed by a prior
         click) completes on a target handle/node, else cancels. Never arms drag. */
      if (f->conn_active) { flow__resolve_connection_at(f, scr); return; }
      f->mouse_down = 1; f->moved = 0; f->down_pos = scr;
      /* HIT PRECEDENCE (trio invariant): handle -> node-body -> pane. A later edge
         package inserts an edge-endpoint test BETWEEN handle and node-body here.
         Handles only hit on hovered/selected/connecting nodes (flow_hit_handle). */
      int hnode = -1; int hidx = flow_hit_handle(f, scr, &hnode);
      if (hidx >= 0 && hnode != -1) {
        const flow_handle *h = flow_node_handle_at(f, hnode, hidx);
        if (h && flow_begin_connection(f, hnode, h->id) == 0) {
          /* grabbed a source handle: do NOT arm node-drag/select. conn_* is orthogonal.
             Clear mouse_down so the trailing release (after the connection resolves) is
             a no-op and never falls into clear_selection/on_pane_click. */
          f->mouse_down = 0; f->down_node = -1; f->drag_node = -1; f->dragging_pan = 0;
          f->down_modsel = 0; f->marquee_active = 0;
          return;
        }
      }
      /* edge-endpoint test (BETWEEN handle and node-body): if the press lands EXACTLY on
         an endpoint cell of the topmost edge under the cursor, arm a reconnect drag and
         skip node-drag/select. Endpoints sit one cell OUTSIDE the node so this never
         steals an ordinary node-body press (require exact cell, not just within tol). */
      int eedge = flow_hit_edge(f, scr, 1);
      if (eedge != -1) {
        flow_pt ss, ts;
        int oks = flow_edge_endpoint_screen(f, flow_get_edge(f, eedge), 0, &ss);
        int okt = flow_edge_endpoint_screen(f, flow_get_edge(f, eedge), 1, &ts);
        int which = -1;
        if (okt && ts.x == scr.x && ts.y == scr.y) which = 1;        /* target endpoint */
        else if (oks && ss.x == scr.x && ss.y == scr.y) which = 0;   /* source endpoint */
        if (which != -1) {
          f->reconnect_edge = eedge; f->reconnect_which = which;
          f->mouse_down = 1; f->down_node = -1; f->drag_node = -1; f->dragging_pan = 0;
          f->down_modsel = 0; f->marquee_active = 0;
          return;
        }
      }
      f->down_node = flow_hit_node(f, scr);
      f->drag_node = -1; f->dragging_pan = 0;
      f->down_modsel = 0; f->marquee_active = 0;
      unsigned mod = ev->mods & (FLOW_MOD_SHIFT | FLOW_MOD_CTRL);
      if (f->down_node != -1) {
        if (mod) {                               /* shift/ctrl-click a node: modify the set NOW */
          if (ev->mods & FLOW_MOD_CTRL) flow_toggle_node(f, f->down_node);  /* toggle */
          else                          flow_select_node(f, f->down_node, 1);/* shift: additive add */
          f->down_modsel = 1;                    /* suppress release replace + on_node_click; arm group drag */
        }
        /* no-mod node press: classify on move/release as before (no select on press) */
      } else if (ev->mods & FLOW_MOD_SHIFT) {    /* shift-drag empty pane: arm marquee (anchor = down_pos) */
        f->marquee_active = 1;
      }
    }
  } else if (ev->type == FLOW_MOUSE_MOTION) {
    if (f->conn_active) {                         /* drag-connect: track free end + reveal candidate */
      if (scr.x != f->down_pos.x || scr.y != f->down_pos.y) f->moved = 1;
      flow_update_connection(f, scr);
      return;
    }
    if (f->reconnect_edge != -1) {                /* reconnect drag: just track movement, no pan/drag */
      if (scr.x != f->down_pos.x || scr.y != f->down_pos.y) f->moved = 1;
      return;
    }
    if (!f->mouse_down) return;
    if (!f->moved && (scr.x != f->down_pos.x || scr.y != f->down_pos.y)) {
      f->moved = 1;                              /* threshold crossed: begin drag, marquee, or pan */
      if (f->marquee_active) {
        f->marquee_on = 1; f->marquee_anchor = f->down_pos;
      } else if (f->down_node != -1) {
        flow_node *nd = flow_get_node(f, f->down_node);
        flow_pt w = flow_to_world(f, f->down_pos), a = flow_node_abs(f, nd);
        f->drag_node = f->down_node; f->drag_grab.x = w.x - a.x; f->drag_grab.y = w.y - a.y;
        f->drag_last_world = flow_to_world(f, f->down_pos);   /* multi-drag delta anchor */
        if (!(nd->flags & FLOW_SELECTED))        /* unselected node: plain drag REPLACES selection */
          flow_select_node(f, f->down_node, 0);  /* selectNodesOnDrag; selected node keeps the set (group drag) */
      } else {
        f->dragging_pan = 1; f->last_mouse = f->down_pos;
      }
    }
    if (f->marquee_on) {                          /* live marquee: replace-select within the box */
      f->marquee_cur = scr;
      flow_pt wa = flow_to_world(f, f->marquee_anchor), wc = flow_to_world(f, scr);
      flow_rect wr = { wa.x < wc.x ? wa.x : wc.x, wa.y < wc.y ? wa.y : wc.y,
                       (wa.x < wc.x ? wc.x - wa.x : wa.x - wc.x),
                       (wa.y < wc.y ? wc.y - wa.y : wa.y - wc.y) };
      flow_select_in_rect(f, wr, f->marquee_mode, 0);
    } else if (f->drag_node != -1) {
      if (flow_selected_count(f) > 1) {           /* MULTI-DRAG: shift the set by per-motion world delta */
        flow_pt w = flow_to_world(f, scr);
        int dx = w.x - f->drag_last_world.x, dy = w.y - f->drag_last_world.y;
        if (dx || dy) {
          /* Apply the delta ONLY to selection ROOTS — selected nodes with no SELECTED
             ancestor. A root's selected descendants follow for free via relative coords;
             applying the delta to them too would double-move. flow_move_node is absolute-in,
             so a root moves to node_abs+delta. (All-top-level sets: every node is a root =>
             byte-identical to the prior per-node delta.) */
          for (int i = 0; i < f->nnodes; i++) {
            if (!(f->nodes[i].flags & FLOW_SELECTED)) continue;
            int root = 1;                          /* root unless a STRICT ancestor is selected */
            int parent = f->nodes[i].parent, guard = 0;
            while (parent != -1 && guard++ < 1024) {
              flow_node *pn = flow_get_node(f, parent); if (!pn) break;
              if (pn->flags & FLOW_SELECTED) { root = 0; break; }
              parent = pn->parent;
            }
            if (!root) continue;
            flow_pt a = flow_node_abs(f, &f->nodes[i]);
            flow_move_node(f, f->nodes[i].id, (flow_pt){ a.x + dx, a.y + dy });
          }
          f->drag_last_world = w;
        }
      } else {                                    /* single node: grab-offset move (unchanged) */
        flow_pt w = flow_to_world(f, scr);
        flow_move_node(f, f->drag_node, (flow_pt){ w.x - f->drag_grab.x, w.y - f->drag_grab.y });
      }
    } else if (f->dragging_pan) {
      flow_pan(f, scr.x - f->last_mouse.x, scr.y - f->last_mouse.y);
      f->last_mouse = scr;
    }
  } else if (ev->type == FLOW_MOUSE_RELEASE) {
    if (f->conn_active) {
      if (f->moved) {                            /* drag-connect: complete on target, else cancel */
        flow__resolve_connection_at(f, scr);
        f->mouse_down = 0; f->moved = 0;
      }
      /* else: the click that BEGAN the connection — stay armed for connectOnClick */
      return;
    }
    if (f->reconnect_edge != -1) {               /* finish an endpoint-reconnect drag */
      if (f->moved) {                            /* dragged: repoint onto a valid node, else leave unchanged */
        int hit = flow_hit_node(f, scr);
        if (hit != -1) flow_reconnect_edge(f, f->reconnect_edge, hit, "", f->reconnect_which);
      } else {                                   /* click on the endpoint, no drag: select the edge */
        flow_select_edge(f, f->reconnect_edge, 0);
      }
      f->reconnect_edge = -1; f->mouse_down = 0; f->moved = 0; f->down_node = -1;
      f->drag_node = -1; f->dragging_pan = 0; f->down_modsel = 0;
      f->marquee_active = 0; f->marquee_on = 0;
      return;
    }
    if (f->mouse_down && !f->moved) {            /* a click, not a drag */
      if (f->down_modsel) {
        /* shift/ctrl-click already applied on press: do NOT replace, do NOT fire on_node_click */
        f->last_click_node = -1;                 /* a modifier-click breaks any double-click pair */
      } else if (f->down_node != -1) {
        flow_select_node(f, f->down_node, 0);
        if (f->cb.on_node_click) f->cb.on_node_click(f, f->down_node, f->cb.user);
        if (f->down_node == f->last_click_node) { /* 2nd consecutive plain click on the SAME node: double-click */
          if (f->cb.on_node_dblclick) f->cb.on_node_dblclick(f, f->down_node, f->cb.user); /* fires AFTER on_node_click */
          f->last_click_node = -1;               /* consume the pair so a 3rd click starts fresh */
        } else {
          f->last_click_node = f->down_node;
        }
      } else {
        int eclick = flow_hit_edge(f, scr, 1);   /* edge-body click-select before clearing/pane-click */
        if (eclick != -1) {
          flow_select_edge(f, eclick, 0);
        } else {
          flow_clear_selection(f);
          if (f->cb.on_pane_click) f->cb.on_pane_click(f, flow_to_world(f, scr), f->cb.user);
        }
        f->last_click_node = -1;                 /* edge/pane click breaks a double-click pair */
      }
    } else if (f->moved && f->drag_node != -1 && flow_selected_count(f) == 1) {
      /* DRAG-TO-REPARENT (single-node drag only for v1). On drop, hit-test the cursor for a
         `group` node — skipping the dragged node AND its own descendants (avoid self-parent).
         A group hit that differs from the current parent reparents (abs preserved => the node
         stays visually put). Dropping on the empty pane while parented detaches to top level.
         flow_hit_node returns the TOPMOST descendant, so we walk the array for a group whose
         footprint contains the drop cell, honouring the same skip rule. */
      int dragged = f->drag_node;
      flow_node *dn = flow_get_node(f, dragged);
      int cur_parent = dn ? dn->parent : -1;
      int target = -1;                            /* the group to drop into, or -1 */
      int lod = flow__lod_for(f, f->view.zoom);
      int *order = flow__node_order(f, 0);        /* topmost-descendant first */
      for (int k = 0; k < f->nnodes; k++) {
        flow_node *cand = &f->nodes[order ? order[k] : k];
        if (strcmp(cand->type, "group") != 0) continue;          /* only group containers */
        if (flow_is_ancestor(f, dragged, cand->id)) continue;    /* skip self + own descendants */
        flow_rect fp = flow__node_footprint(f, cand, lod);
        if (flow_rect_contains(fp, scr)) { target = cand->id; break; }
      }
      free(order);
      if (target != -1) {
        if (target != cur_parent) flow_set_parent(f, dragged, target);
      } else if (cur_parent != -1) {
        flow_set_parent(f, dragged, -1);          /* dropped on empty pane: detach to top level */
      }
    }
    /* marquee finalize: selection already applied during motion; just clear state.
       A marqueed drag sets moved==1, so on_pane_click was never fired. */
    if (f->moved) f->last_click_node = -1;       /* any drag breaks a double-click pair */
    f->mouse_down = 0; f->moved = 0; f->drag_node = -1; f->dragging_pan = 0; f->down_node = -1;
    f->down_modsel = 0; f->marquee_active = 0; f->marquee_on = 0;
  }
}
#endif
/* ===================== src/flow_term.h ===================== */
/* ===== terminal: raw mode, alt-screen, size (impl-only POSIX deps) ===== */
void flow_term_setup(void);
void flow_term_restore(void);
int  flow_term_size(int *cols, int *rows);

#ifdef FLOW_IMPLEMENTATION
#include <termios.h>
#include <unistd.h>
#include <sys/ioctl.h>
static struct termios flow__saved_tio;
void flow_term_setup(void) {
  struct termios raw; tcgetattr(STDIN_FILENO, &flow__saved_tio); raw = flow__saved_tio;
  raw.c_lflag &= ~(ECHO | ICANON);
  tcsetattr(STDIN_FILENO, TCSAFLUSH, &raw);
  /* alt-screen, clear, hide cursor; enable SGR mouse (click+drag+wheel) */
  printf("\x1b[?1049h\x1b[2J\x1b[?25l\x1b[?1000h\x1b[?1002h\x1b[?1006h"); fflush(stdout);
}
void flow_term_restore(void) {
  printf("\x1b[?1006l\x1b[?1002l\x1b[?1000l\x1b[0m\x1b[?25h\x1b[?1049l"); fflush(stdout);
  tcsetattr(STDIN_FILENO, TCSAFLUSH, &flow__saved_tio);
}
int flow_term_size(int *cols, int *rows) {
  struct winsize ws;
  if (ioctl(STDOUT_FILENO, TIOCGWINSZ, &ws) != 0 || ws.ws_col == 0) return -1;
  *cols = ws.ws_col; *rows = ws.ws_row; return 0;
}
#endif
/* ===================== src/flow_run.h ===================== */
/* ===== present (diff+flush), feed (arrow-key pan), run loop ===== */
void flow_present(flow_t *f);
void flow_feed(flow_t *f, const char *bytes, int n);
void flow_run(flow_t *f);

#ifdef FLOW_IMPLEMENTATION
void flow_present(flow_t *f) {
  flow_cell *back = (flow_cell*)calloc((size_t)f->cols * f->rows, sizeof(flow_cell));
  flow_render(f, back, f->cols, f->rows);
  char *esc = flow_diff_emit(f->front, back, f->cols, f->rows);
  fputs(esc, stdout); fflush(stdout); free(esc);
  memcpy(f->front, back, (size_t)f->cols * f->rows * sizeof(flow_cell));
  free(back);
}
void flow_feed(flow_t *f, const char *b, int n) {
  int i = 0;
  while (i < n) {
    if (b[i] == '\x1b' && i + 2 < n && b[i+1] == '[' && b[i+2] == '<') {
      flow_mouse_event ev; int used = flow_parse_mouse(b + i, n - i, &ev);
      if (used > 0) { flow_handle_mouse(f, &ev); i += used; continue; }
    }
    int dk = flow_dispatch_key(f, b + i, n - i);   /* registry/built-in keys (NOT bare arrows, NOT 'q') */
    if (dk > 0) { i += dk; continue; }
    if (b[i] == '\x1b' && i + 2 < n && b[i+1] == '[') {
      switch (b[i+2]) {                          /* arrow-key pan */
        case 'A': flow_pan(f, 0,  1); i += 3; continue;   /* up    */
        case 'B': flow_pan(f, 0, -1); i += 3; continue;   /* down  */
        case 'C': flow_pan(f, -1, 0); i += 3; continue;   /* right */
        case 'D': flow_pan(f,  1, 0); i += 3; continue;   /* left  */
        default: break;
      }
    }
    /* +/- zoom (keyboard has no cursor, so center on the screen centre). Placed AFTER
       flow_dispatch_key so a user flow_bind_key('+') override still wins via the registry. */
    if (b[i] == '+' || b[i] == '=') { flow_zoom_in (f, (flow_pt){ f->cols / 2, f->rows / 2 }); i++; continue; }
    if (b[i] == '-' || b[i] == '_') { flow_zoom_out(f, (flow_pt){ f->cols / 2, f->rows / 2 }); i++; continue; }
    /* lone ESC (not the start of a CSI) cancels an in-flight connection. Real
       mouse/arrow/Delete sequences all have b[i+1]=='[' and are consumed above. */
    if (b[i] == '\x1b' && (i + 1 >= n || b[i+1] != '[')) { flow_cancel_connection(f); i++; continue; }
    i++;
  }
}
void flow_run(flow_t *f) {
  int cols, rows;
  if (flow_term_size(&cols, &rows) == 0) flow_resize(f, cols, rows);
  flow_term_setup(); f->running = 1;
  flow_present(f);
  char buf[64];
  while (f->running) {
    int n = (int)read(STDIN_FILENO, buf, sizeof buf);
    if (n <= 0) break;
    for (int i = 0; i < n; i++) if (buf[i] == 'q') f->running = 0;
    flow_feed(f, buf, n);
    flow_present(f);
  }
  flow_term_restore();
}
#endif
#endif /* FLOW_H */
